SELECT Customer.[Geographical Zone], [Geographical Zone].Description, [Geographical Zone].[Credit Manager], Customer.Name, Customer.No_, [ControlloSbilanciamentoAssegni-step1].[Letter No_], [ControlloSbilanciamentoAssegni-step1].DataRegistrazione, [ControlloSbilanciamentoAssegni-step1].DataScadenza, [ControlloSbilanciamentoAssegni-step1].ImportoResiduoSimulatoInValuta, [ControlloSbilanciamentoAssegni-step1].ImportoResiduoSimulatoEuro, [ControlloSbilanciamentoAssegni-step1].CodValuta, [ControlloSbilanciamentoAssegni-step0].ImportoResiduoInValuta, [ControlloSbilanciamentoAssegni-step0].ImportoResiduoEuro, Round(([importoresiduosimulatoinvaluta]+Nz([importoresiduoinvaluta]))*10000)/10000 AS deltaValuta, Round(([importoresiduosimulatoeuro]+Nz([importoresiduoeuro]))*10000)/10000 AS deltaEuro
FROM (([ControlloSbilanciamentoAssegni-step1] LEFT JOIN [ControlloSbilanciamentoAssegni-step0] ON [ControlloSbilanciamentoAssegni-step1].[Letter No_] = [ControlloSbilanciamentoAssegni-step0].[Letter No_]) INNER JOIN Customer ON [ControlloSbilanciamentoAssegni-step1].[Customer No_] = Customer.No_) LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code
ORDER BY Customer.No_, [ControlloSbilanciamentoAssegni-step1].[Letter No_], [ControlloSbilanciamentoAssegni-step1].DataScadenza;

